SourceCode.Declaration:
[DataContractAttribute]
class ETGAPayLedgerJournalTransContract
{
    private TransDate tansDate;
    CurrencyCode currencyCode;
    ExchRate exchRate;
    LedgerJournalACType accountType, OffsetAccountType;
    DimensionDynamicAccount account, OffsetAccount;
    AmountCurDebit debit;
    AmountCurCredit credit;
    LedgerJournalTransTxt txt;
    PostingProfile postingProfile;
    PaymMode methodOfPayment;
    InvoiceId invoiceId;
    LedgerJournalId ledgerJournalId;
    PurchIdBase purchId;
    str productCode, partNo, supplierInvoiceNo, bLNo, deliveryReference, airFreightCharges, descriptionDetails, uOM, amountInDocCurrency, materialCode, material;
    real quantity, unitPrice, amount;
    date transferDateBLDate, dateofissue, dateofsail;

}

