/// <summary>
/// Transaction Date
/// </summary>
[DataMemberAttribute('TransDate')]
public TransDate parmTransDate(TransDate _tansDate = tansDate)
{
    if (!prmIsDefault(_tansDate))
    {
        tansDate = _tansDate;
    }
    return tansDate;
}

